      })}
      {localTrip.items.length === 0 && <div className="text-center py-20 text-slate-400"><Layers size={48} className="mx-auto mb-4 opacity-50" /><p>此行程沒有物品，請點擊編輯加入物品。</p></div>}
    </div>
  );
};
