                {!folder.isSystem && <button onClick={(e) => handleDeleteFolder(e, folder.id)} className="opacity-0 group-hover:opacity-100 text-slate-400 hover:text-red-500 transition-opacity p-1"><Trash2 size={14} /></button>}
              </div>
