    const updatedTrip = { ...localTrip, items: updatedItems };
    const allChecked = updatedItems.every(i => i.checked);
    updatedTrip.status = allChecked ? 'completed' : 'active';
    setLocalTrip(updatedTrip);
    onUpdateTrip(updatedTrip);
