      });

      // 2. Sync Trips to 'trips' collection for sharing
      for (const trip of trips) {
          if (trip.userId === userId) {
              await setDoc(doc(db, "trips", trip.id), trip);
          }
      }
      return { success: true };
    } catch (error) {
      console.error("Upload failed:", error);
      return { success: false, error };
    }
  },
