              const updatedTrip = { ...localTrip, sharedWith: localTrip.sharedWith?.filter(id => id !== userId) };
              setLocalTrip(updatedTrip);
              onUpdateTrip(updatedTrip);
          } else {
              alert('❌ 取消失敗');
          }
      }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-20">
